    /// Size of the AABB along each local axis.
    pub fn size(self) -> Vec3 {
        let d = self.def();
        d.aabb_max - d.aabb_min
    }

    /// Center of the AABB in the model's local space.
    pub fn local_center(self) -> Vec3 {
        let d = self.def();
        (d.aabb_min + d.aabb_max) * 0.5
    }
